import { useState, useEffect } from 'react';
import { Spinner, Modal, Btn, Badge, useToast } from '../../components/shared/index.jsx';
import { getJobs, getJobRanking, uploadAndRankCVs } from '../../api/index.js';

export function HRCVRankingPage() {
  const toast = useToast();

  const [jobs, setJobs]           = useState([]);
  const [selectedJob, setSelectedJob] = useState(null);
  const [rankings, setRankings]   = useState([]);
  const [loading, setLoading]     = useState(false);
  const [rankingLoading, setRankingLoading] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState([]);

  useEffect(() => {
    loadJobs();
  }, []);

  const loadJobs = async () => {
    setLoading(true);
    try {
      const data = await getJobs();
      setJobs(data);
    } catch (err) {
      toast('Failed to load jobs', 'error');
    }
    setLoading(false);
  };

  const handleFileChange = (e) => {
    setUploadedFiles(Array.from(e.target.files));
  };

  const handleRankCVs = async () => {
    if (!selectedJob) {
      toast('Please select a job', 'error');
      return;
    }

    setRankingLoading(true);
    try {
      let data;
      if (uploadedFiles.length > 0) {
        // Upload and rank new CVs
        const formData = new FormData();
        uploadedFiles.forEach(file => formData.append('cvs', file));
        data = await uploadAndRankCVs(selectedJob.id, formData);
      } else {
        // Rank existing submissions
        data = await getJobRanking(selectedJob.id);
      }
      setRankings(data);
    } catch (err) {
      toast('Failed to rank CVs', 'error');
    }
    setRankingLoading(false);
  };

  return (
    <div style={{ maxWidth: 1280, margin: '0 auto', padding: '40px 32px 80px' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 28, flexWrap: 'wrap', gap: 16 }}>
        <div>
          <h2 style={{ fontSize: 22, fontWeight: 700, marginBottom: 4 }}>CV Ranking & Analysis</h2>
          <p style={{ fontSize: 13.5, color: 'var(--gray-500)' }}>AI-powered candidate evaluation using semantic analysis and skill matching</p>
        </div>
      </div>

      {/* Job Selection Card */}
      <div style={{ background: 'var(--white)', borderRadius: 20, padding: '24px', border: '1px solid #EAECF0', marginBottom: 24 }}>
        <h3 style={{ fontSize: 16, fontWeight: 600, marginBottom: 16, color: 'var(--gray-900)' }}>Select Job Position</h3>

        <div style={{ marginBottom: 16 }}>
          <label style={{ display: 'block', fontSize: 12, fontWeight: 700, color: 'var(--gray-700)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.06em' }}>
            Job Position
          </label>
          <select
            value={selectedJob?.id || ''}
            onChange={(e) => {
              const job = jobs.find(j => j.id == e.target.value);
              setSelectedJob(job);
              setRankings([]);
              setUploadedFiles([]);
            }}
            style={{
              width: '100%', padding: '11px 14px', background: 'var(--gray-100)',
              border: '2px solid transparent', borderRadius: 12, fontSize: 13.5,
              outline: 'none', fontFamily: 'var(--sans)', color: 'var(--gray-900)',
            }}
          >
            <option value="">Choose a job position...</option>
            {jobs.map(job => (
              <option key={job.id} value={job.id}>{job.title}</option>
            ))}
          </select>
        </div>

        {/* File Upload */}
        <div style={{ marginBottom: 20 }}>
          <label style={{ display: 'block', fontSize: 12, fontWeight: 700, color: 'var(--gray-700)', marginBottom: 6, textTransform: 'uppercase', letterSpacing: '.06em' }}>
            Upload Additional CVs (Optional)
          </label>
          <input
            type="file"
            multiple
            accept=".pdf,.txt"
            onChange={handleFileChange}
            style={{
              width: '100%', padding: '11px 14px', background: 'var(--gray-100)',
              border: '2px solid transparent', borderRadius: 12, fontSize: 13.5,
              outline: 'none', fontFamily: 'var(--sans)', color: 'var(--gray-900)',
            }}
          />
          <p style={{ fontSize: 12, color: 'var(--gray-500)', marginTop: 4 }}>
            Leave empty to rank existing candidate submissions. Supports PDF and TXT files.
          </p>
        </div>

        {uploadedFiles.length > 0 && (
          <div style={{ marginBottom: 16, padding: 12, background: 'var(--gray-50)', borderRadius: 8 }}>
            <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-700)', marginBottom: 8 }}>
              Selected Files ({uploadedFiles.length}):
            </div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
              {uploadedFiles.map((file, index) => (
                <Badge key={index} color="blue">{file.name}</Badge>
              ))}
            </div>
          </div>
        )}

        {/* Rank Button */}
        <Btn
          onClick={handleRankCVs}
          disabled={rankingLoading || !selectedJob}
          style={{ minWidth: 160 }}
        >
          {rankingLoading ? (
            <><Spinner size={16} />&nbsp;Analyzing CVs...</>
          ) : (
            <><svg width="16" height="16" fill="none" stroke="#fff" strokeWidth="2.5" viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg>&nbsp;Rank CVs</>
          )}
        </Btn>
      </div>

      {/* Rankings Table */}
      {rankings.length > 0 && (
        <div style={{ background: 'var(--white)', borderRadius: 24, border: '1px solid #EAECF0', overflow: 'hidden' }}>
          <div style={{ padding: '20px 24px', borderBottom: '1px solid #EAECF0' }}>
            <h3 style={{ fontSize: 16, fontWeight: 600, margin: 0, color: 'var(--gray-900)' }}>
              Ranked Candidates ({rankings.length})
            </h3>
            <p style={{ fontSize: 12, color: 'var(--gray-500)', margin: '4px 0 0 0' }}>
              AI-powered ranking using TF-IDF similarity (70%) and skill matching (30%)
            </p>
          </div>

          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ background: 'var(--gray-50)' }}>
                  {['Rank', 'Candidate', 'Final Score', 'Similarity Score', 'Skill Match', 'Matched Skills', 'Evidence'].map(h => (
                    <th key={h} style={{ padding: '14px 20px', textAlign: 'left', fontSize: 11, fontWeight: 700, color: 'var(--gray-500)', textTransform: 'uppercase', letterSpacing: '.08em', borderBottom: '1px solid #EAECF0' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {rankings.map((rank, index) => (
                  <tr key={rank.submission_id || rank.file_name} style={{ borderBottom: '1px solid #EAECF0' }}>
                    <td style={{ padding: '16px 20px', fontSize: 13, fontWeight: 600, color: 'var(--gray-900)' }}>
                      #{index + 1}
                    </td>
                    <td style={{ padding: '16px 20px', fontSize: 13, color: 'var(--gray-900)' }}>
                      {rank.candidate_name || rank.file_name}
                    </td>
                    <td style={{ padding: '16px 20px', fontSize: 13, fontWeight: 600 }}>
                      <span style={{
                        color: rank.final_score >= 80 ? '#22C55E' : rank.final_score >= 60 ? '#F59E0B' : '#E8321A',
                        fontWeight: 700
                      }}>
                        {rank.final_score}%
                      </span>
                    </td>
                    <td style={{ padding: '16px 20px', fontSize: 13, color: 'var(--gray-700)' }}>
                      {rank.similarity_score}%
                    </td>
                    <td style={{ padding: '16px 20px', fontSize: 13, color: 'var(--gray-700)' }}>
                      {rank.skill_match_pct}%
                    </td>
                    <td style={{ padding: '16px 20px' }}>
                      {rank.matched_skills && rank.matched_skills.length > 0 ? (
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                          {rank.matched_skills.slice(0, 3).map(skill => (
                            <Badge key={skill} color="green" style={{ fontSize: 11 }}>{skill}</Badge>
                          ))}
                          {rank.matched_skills.length > 3 && (
                            <Badge color="gray" style={{ fontSize: 11 }}>+{rank.matched_skills.length - 3} more</Badge>
                          )}
                        </div>
                      ) : (
                        <span style={{ fontSize: 12, color: 'var(--gray-400)' }}>None</span>
                      )}
                    </td>
                    <td style={{ padding: '16px 20px', maxWidth: 300 }}>
                      {rank.evidence && rank.evidence.length > 0 ? (
                        <div style={{ fontSize: 12, color: 'var(--gray-600)', lineHeight: 1.4 }}>
                          {rank.evidence.slice(0, 2).map((evidence, i) => (
                            <div key={i} style={{ marginBottom: 4 }}>{evidence}</div>
                          ))}
                          {rank.evidence.length > 2 && (
                            <div style={{ color: 'var(--gray-400)' }}>+{rank.evidence.length - 2} more skills...</div>
                          )}
                        </div>
                      ) : (
                        <span style={{ fontSize: 12, color: 'var(--gray-400)' }}>No evidence found</span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* How it works section */}
      {rankings.length > 0 && (
        <div style={{ background: 'var(--white)', borderRadius: 20, padding: '24px', border: '1px solid #EAECF0', marginTop: 24 }}>
          <h3 style={{ fontSize: 16, fontWeight: 600, marginBottom: 16, color: 'var(--gray-900)' }}>
            How the AI Ranking Works
          </h3>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: 20 }}>
            <div>
              <h4 style={{ fontSize: 14, fontWeight: 600, color: 'var(--gray-900)', marginBottom: 8 }}>
                1. Text Similarity Analysis (70% weight)
              </h4>
              <p style={{ fontSize: 13, color: 'var(--gray-600)', lineHeight: 1.5 }}>
                Uses TF-IDF vectorization to compare job description with CV content. Higher scores indicate
                better semantic match between job requirements and candidate experience.
              </p>
            </div>

            <div>
              <h4 style={{ fontSize: 14, fontWeight: 600, color: 'var(--gray-900)', marginBottom: 8 }}>
                2. Skill Matching (30% weight)
              </h4>
              <p style={{ fontSize: 13, color: 'var(--gray-600)', lineHeight: 1.5 }}>
                Matches required job skills against candidate skills using fuzzy matching and synonyms.
                Considers skill frequency and context in the CV text.
              </p>
            </div>

            <div>
              <h4 style={{ fontSize: 14, fontWeight: 600, color: 'var(--gray-900)', marginBottom: 8 }}>
                3. Final Score Calculation
              </h4>
              <p style={{ fontSize: 13, color: 'var(--gray-600)', lineHeight: 1.5 }}>
                Combines similarity and skill scores: <code style={{ background: 'var(--gray-100)', padding: '2px 4px', borderRadius: 4 }}>Final = 0.7 × Similarity + 0.3 × Skills</code>
              </p>
            </div>
          </div>
        </div>
      )}

      {loading && <Spinner />}
    </div>
  );
}
